// Live embedded base64 fonts to guarantee 100% pixel-consistent layouts
const INTER_REGULAR = "";
const INTER_BOLD = "";
const LORA_REGULAR = "";
const LORA_BOLD = "";

function getEmbeddedFontsCSS() {
    return `
    @font-face {
        font-family: 'Inter';
        font-style: normal;
        font-weight: 400;
        font-display: block;
        src: url(data:font/woff2;charset=utf-8;base64,${INTER_REGULAR}) format('woff2');
    }
    @font-face {
        font-family: 'Inter';
        font-style: normal;
        font-weight: 700;
        font-display: block;
        src: url(data:font/woff2;charset=utf-8;base64,${INTER_BOLD}) format('woff2');
    }
    @font-face {
        font-family: 'Lora';
        font-style: normal;
        font-weight: 400;
        font-display: block;
        src: url(data:font/woff2;charset=utf-8;base64,${LORA_REGULAR}) format('woff2');
    }
    @font-face {
        font-family: 'Lora';
        font-style: normal;
        font-weight: 700;
        font-display: block;
        src: url(data:font/woff2;charset=utf-8;base64,${LORA_BOLD}) format('woff2');
    }
    `;
}

module.exports = {
    getEmbeddedFontsCSS
};
